final class CryptoManager {
    static let shared = CryptoManager()
    private let keyTag = "com.bankapp.encryptionKey"

    private init() {}

    private func loadOrGenerateSymmetricKey() throws -> SymmetricKey {
        if let existingKey = try? retrieveKey() {
            return existingKey
        } else {
            let key = SymmetricKey(size: .bits256)
            try storeKey(key)
            return key
        }
    }

    private func storeKey(_ key: SymmetricKey) throws {
        let keyData = key.withUnsafeBytes { Data(Array($0)) }

        let query: [String: Any] = [
            kSecClass as String:            kSecClassKey,
            kSecAttrApplicationTag as String: keyTag,
            kSecAttrKeyType as String:      kSecAttrKeyTypeAES,
            kSecValueData as String:        keyData,
            kSecAttrAccessible as String:   kSecAttrAccessibleAfterFirstUnlock
        ]

        SecItemDelete(query as CFDictionary)
        let status = SecItemAdd(query as CFDictionary, nil)

        guard status == errSecSuccess else { throw CryptoError.keyGenerationFailed }
    }

    private func retrieveKey() throws -> SymmetricKey {
        let query: [String: Any] = [
            kSecClass as String:            kSecClassKey,
            kSecAttrApplicationTag as String: keyTag,
            kSecReturnData as String:       true
        ]

        var item: CFTypeRef?
        let status = SecItemCopyMatching(query as CFDictionary, &item)
        guard status == errSecSuccess,
              let keyData = item as? Data else { throw CryptoError.keyGenerationFailed }

        return SymmetricKey(data: keyData)
    }

    func encrypt(_ data: Data) throws -> Data {
        let key = try loadOrGenerateSymmetricKey()
        do {
            let sealedBox = try AES.GCM.seal(data, using: key)
            return sealedBox.combined!
        } catch {
            throw CryptoError.encryptionFailed
        }
    }

    func decrypt(_ data: Data) throws -> Data {
        let key = try loadOrGenerateSymmetricKey()
        do {
            let sealedBox = try AES.GCM.SealedBox(combined: data)
            return try AES.GCM.open(sealedBox, using: key)
        } catch {
            throw CryptoError.decryptionFailed
        }
    }
}

// MARK: - Secure Storage

final class SecureStorage {
    static let shared = SecureStorage()
    private let fileURL: URL

    private init() {
        let directory = FileManager.default.urls(for: .applicationSupportDirectory, in: .userDomainMask)[0]
        if !FileManager.default.fileExists(atPath: directory.path) {
            try? FileManager.default.createDirectory(at: directory, withIntermediateDirectories: true)
        }
        fileURL = directory.appendingPathComponent("bank_data.enc")
    }

    func save(accounts: [Account]) throws {
        let encoder = JSONEncoder()
        let data = try encoder.encode(accounts)
        let encrypted = try CryptoManager.shared.encrypt(data)
        try encrypted.write(to: fileURL, options: .atomic)
    }

    func load() throws -> [Account] {
        guard FileManager.default.fileExists(atPath: fileURL.path) else { return [] }
        let encrypted = try Data(contentsOf: fileURL)
        let decrypted = try CryptoManager.shared.decrypt(encrypted)
        let decoder = JSONDecoder()
        return try decoder.decode([Account].self, from: decrypted)
    }
}

// MARK: - Transaction Processor

final class TransactionProcessor {
    static let shared = TransactionProcessor()
    private let queue = DispatchQueue(label: "com.bankapp.transactionQueue", attributes: .concurrent)

    func process(_ transaction: Transaction,
                 for accountID: UUID,
                 completion: @escaping (Result<[Account], Error>) -> Void) {
        queue.async(flags: .barrier) {
            do {
                var accounts = try SecureStorage.shared.load()
                guard let index = accounts.firstIndex(where: { $0.id == accountID }) else {
                    throw NSError(domain: "AccountNotFound", code: 1)
                }

                var account = accounts[index]
                switch transaction.type {
                case .deposit:
                    account.balance += transaction.amount
                case .withdrawal:
                    account.balance -= transaction.amount
                case .transfer:
                    // Extend for transfers between accounts.
                    account.balance -= transaction.amount
                }

                account.transactions.append(transaction)
                accounts[index] = account
                try SecureStorage.shared.save(accounts: accounts)
                DispatchQueue.main.async { completion(.success(accounts)) }
            } catch {
                DispatchQueue.main.async { completion(.failure(error)) }
            }
        }
    }

    func accounts(completion: @escaping (Result<[Account], Error>) -> Void) {
        queue.async {
            do {
                let accounts = try SecureStorage.shared.load()
                DispatchQueue.main.async { completion(.success(accounts)) }
            } catch {
                DispatchQueue.main.async { completion(.failure(error)) }
            }
        }
    }
}

// MARK: - ViewModel

final class BankingViewModel: ObservableObject {
    @Published private(set) var accounts: [Account] = []
    @Published var errorMessage: String?

    init() {
        fetchAccounts()
    }

    func fetchAccounts() {
        TransactionProcessor.shared.accounts { [weak self] result in
            switch result {
            case .success(let accounts):
                self?.accounts = accounts
            case .failure(let error):
                self?.errorMessage = error.localizedDescription
            }
        }
    }

    func makeTransaction(amount: Decimal,
                         description: String,
                         type: Transaction.TransactionType,
                         accountID: UUID) {
        let transaction = Transaction(id: UUID(),
                                      date: Date(),
                                      type: type,
                                      amount: amount,
                                      description: description)
        TransactionProcessor.shared.process(transaction, for: accountID) { [weak self] result in
            switch result {
            case .success(let accounts):
                self?.accounts = accounts
            case .failure(let error):
                self?.errorMessage = error.localizedDescription
            }
        }
    }

    func addAccount(name: String, initialBalance: Decimal) {
        let account = Account(id: UUID(),
                              name: name,
                              balance: initialBalance,
                              transactions: [])
        var newAccounts = accounts
        newAccounts.append(account)
        do {
            try SecureStorage.shared.save(accounts: newAccounts)
            accounts = newAccounts
        } catch {
            errorMessage = error.localizedDescription
        }
    }
}

// MARK: - Views

struct ContentView: View {
    @StateObject private var viewModel = BankingViewModel()
    @State private var showingAddAccount = false
    @State private var selectedAccount: Account?

    var body: some View {
        NavigationView {
            List {
                ForEach(viewModel.accounts) { account in
                    Button(action: { selectedAccount = account }) {
                        HStack {
                            Text(account.name)
                            Spacer()
                            Text(account.balance, format: .currency(code: Locale.current.currency?.identifier ?? "USD"))
                        }
                    }
                }
            }
            .navigationTitle("Accounts")
            .toolbar {
                Button(action: { showingAddAccount = true }) {
                    Label("Add Account", systemImage: "plus")
                }
            }
            .sheet(item: $selectedAccount) { account in
                AccountDetailView(account: account, viewModel: viewModel)
            }
            .sheet(isPresented: $showingAddAccount) {
                AddAccountView(viewModel: viewModel)
            }
            .alert(item: Binding(
                get: { viewModel.errorMessage.map { ErrorWrapper(message: $0) } },
                set: { _ in viewModel.errorMessage = nil }
            )) { wrapper in
                Alert(title: Text("Error"), message: Text(wrapper.message), dismissButton: .default(Text("OK")))
            }
        }
    }
}

struct AccountDetailView: View {
    let account: Account
    @ObservedObject var viewModel: BankingViewModel
    @State private var amountText = ""
    @State private var descriptionText = ""

    var body: some View {
        VStack {
            Text(account.name)
                .font(.largeTitle)
            Text(account.balance, format: .currency(code: Locale.current.currency?.identifier ?? "USD"))
                .font(.title)
                .padding()

            Form {
                Section(header: Text("New Transaction")) {
                    TextField("Amount", text: $amountText)
                        .keyboardType(.decimalPad)
                    TextField("Description", text: $descriptionText)
                    HStack {
                        Button("Deposit") {
                            submit(type: .deposit)
                        }
                        Spacer()
                        Button("Withdraw") {
                            submit(type: .withdrawal)
                        }
                    }
                }

                Section(header: Text("Transactions")) {
                    List(account.transactions.sorted { $0.date > $1.date }) { txn in
                        HStack {
                            Text(txn.description)
                            Spacer()
                            Text(txn.amount, format: .currency(code: Locale.current.currency?.identifier ?? "USD"))
                                .foregroundColor(txn.type == .withdrawal ? .red : .green)
                        }
                    }
                }
            }
        }
        .padding()
    }

    private func submit(type: Transaction.TransactionType) {
        guard let amount = Decimal(string: amountText) else { return }
        viewModel.makeTransaction(amount: amount,
                                  description: descriptionText,
                                  type: type,
                                  accountID: account.id)
        amountText = ""
        descriptionText = ""
    }
}

struct AddAccountView: View {
    @Environment(\.dismiss) private var dismiss
    @ObservedObject var viewModel: BankingViewModel
    @State private var name = ""
    @State private var balanceText = ""

    var body: some View {
        NavigationView {
            Form {
                TextField("Account Name", text: $name)
                TextField("Initial Balance", text: $balanceText)
                    .keyboardType(.decimalPad)
            }
            .navigationTitle("New Account")
            .toolbar {
                ToolbarItem(placement: .confirmationAction) {
                    Button("Save") {
                        guard let balance = Decimal(string: balanceText), !name.isEmpty else { return }
                        viewModel.addAccount(name: name, initialBalance: balance)
                        dismiss()
                    }
                }
                ToolbarItem(placement: .cancellationAction) {
                    Button("Cancel") { dismiss() }
                }
            }
        }
    }
}

